#include<bits/stdc++.h>

using namespace std;

int main(){
	string a; 
	cin>>a;
	int z; // 整数部分的长度
	string fuhao; 
	if(a =="0")return 0;
	string b; 
	for(int i=0;i<int(a.size());i++){
		if(isdigit(a[i])){
			z++;
		}else{
			fuhao = a[i];
			break;
		}
	}

	int start = z-1; // 整数遍历的开始
	while(a[start]=='0'&&start>0){
		start--;
	}
	for(int i=start;i>=0;i--){
		b+=a[i];
	}
	if(fuhao == "%"){
		b+="%";
	}else if(fuhao=="/"){

		b+="/";
		int start = a.size()-1;
		while(a[start]=='0'&&start>z+1){
			start--;
			// 1000/1000
		}
		for(int i=start;i>=z+1;i--){
			b+=a[i];
		}
	}else if(fuhao=="."){
		b+=".";
		int end = z+1;

		while(a[end]=='0'&&end<int(a.size()-1)){
			end++;
		}
		for(int i=a.size()-1;i>=end;i--){
			b+=a[i];
		}
	}
	cout<<b;
	
	
	
	return 0;
}
